import {useMemo} from 'react';
import type {IStyleClasses} from '@lmb-it/kitsconcerto-types';
import {style} from '@lmb-it/kitsconcertomobile/Factory/helpers/style';

/**
 * Native focus-style helper.
 * Merges `_focus` styles into the computed style object when `isFocused` is true.
 * Returns a React Native ViewStyle object ready for the `style` prop.
 */
export function useFocusStyles(
    themeStyle: IStyleClasses | undefined,
    isFocused: boolean,
) {
    return useMemo(() => {
        if (!themeStyle) return {};
        const {_focus, _hover, ...base} = themeStyle as any;
        const baseStyle = style(base);
        if (!isFocused || !_focus) return baseStyle;
        const focusStyle = style(_focus);
        return {...baseStyle, ...focusStyle};
    }, [themeStyle, isFocused]);
}

export default useFocusStyles;
